class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable returns null for empty
        // vars on Unix. Use GetEnvironmentVariables() to detect existence.
        var exists = Environment.GetEnvironmentVariables().Contains("MY_FLAG");
        if (!exists)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

